1. errors.py 업데이트:

```python
class MCPError(Exception):
    """MCP 서버 기본 예외"""
    pass

class InvalidParameterError(MCPError):
    """잘못된 파라미터 예외"""
    def __init__(self, param_name: str, message: str):
        self.param_name = param_name
        self.message = message
        super().__init__(f"{param_name}: {message}")

class APIError(MCPError):
    """API 호출 실패 예외"""
    def __init__(self, operation: str, message: str):
        self.operation = operation
        self.message = message
        super().__init__(f"{operation} 실패: {message}")

def validate_stock_code(code: str) -> None:
    """종목코드 유효성 검사"""
    if not code or len(code) != 6 or not code.isdigit():
        raise InvalidParameterError("code", "종목코드는 6자리 숫자여야 합니다")

def validate_date(date: str, param_name: str = "date") -> None:
    """날짜 형식 유효성 검사"""
    if date and (len(date) != 8 or not date.isdigit()):
        raise InvalidParameterError(param_name, "날짜는 YYYYMMDD 형식이어야 합니다")
```

